import React, { useState } from 'react';
import { TextField, Button, Typography, Container, Box, Alert, ToggleButton, ToggleButtonGroup } from '@mui/material';
import axios from 'axios';

const SignupPage = () => {
  const [form, setForm] = useState({
    fullName: '',
    email: '',
    mobile: '',
    password: '',
    role: 'USER',
  });
  const [error, setError] = useState('');

  const handleChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value });
  };

  const handleRoleChange = (_, newRole) => {
    if (newRole) setForm({ ...form, role: newRole });
  };

  const handleSignup = async () => {
    try {
      const res = await axios.post('http://localhost:5000/api/auth/signup', form);
      alert(res.data.message);
      setError('');
    } catch (err) {
      setError(err.response?.data?.error || 'Server error during signup');
    }
  };

  return (
    <Container maxWidth="xs">
      <Box mt={8} textAlign="center">
        <Typography variant="h4">Rider App</Typography>
        <Typography variant="subtitle1">Create your account</Typography>
        {error && <Alert severity="error">{error}</Alert>}
        <TextField
          fullWidth
          label="Full Name"
          name="fullName"
          margin="normal"
          value={form.fullName}
          onChange={handleChange}
        />
        <TextField
          fullWidth
          label="Email"
          name="email"
          margin="normal"
          value={form.email}
          onChange={handleChange}
        />
        <TextField
          fullWidth
          label="Mobile Number"
          name="mobile"
          margin="normal"
          value={form.mobile}
          onChange={handleChange}
        />
        <TextField
          fullWidth
          label="Password"
          name="password"
          type="password"
          margin="normal"
          value={form.password}
          onChange={handleChange}
        />
        <ToggleButtonGroup
          color="primary"
          value={form.role}
          exclusive
          onChange={handleRoleChange}
          sx={{ mt: 2 }}
        >
          <ToggleButton value="USER">USER</ToggleButton>
          <ToggleButton value="OWNER">OWNER</ToggleButton>
        </ToggleButtonGroup>
        <Button fullWidth variant="contained" color="warning" sx={{ mt: 2 }} onClick={handleSignup}>
          REGISTER
        </Button>
      </Box>
    </Container>
  );
};

export default SignupPage;
